CREATE TABLE IF NOT EXISTS `message_reactions` (
	`id` int AUTO_INCREMENT NOT NULL,
	`messageId` int NOT NULL,
	`userId` int NOT NULL,
	`reactionType` varchar(20) NOT NULL,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `message_reactions_id` PRIMARY KEY(`id`)
);

ALTER TABLE `conversations` ADD COLUMN IF NOT EXISTS `lastMessage` text;
ALTER TABLE `conversations` ADD COLUMN IF NOT EXISTS `isPinned` tinyint DEFAULT 0 NOT NULL;
ALTER TABLE `conversations` ADD COLUMN IF NOT EXISTS `isArchived` tinyint DEFAULT 0 NOT NULL;
ALTER TABLE `conversations` ADD COLUMN IF NOT EXISTS `label` varchar(50);
ALTER TABLE `conversations` ADD COLUMN IF NOT EXISTS `labelColor` varchar(20);
ALTER TABLE `messages` ADD COLUMN IF NOT EXISTS `readAt` timestamp;
ALTER TABLE `messages` ADD COLUMN IF NOT EXISTS `attachmentUrl` text;
ALTER TABLE `messages` ADD COLUMN IF NOT EXISTS `attachmentType` varchar(50);
ALTER TABLE `messages` ADD COLUMN IF NOT EXISTS `attachmentName` varchar(255);

